
.status-card {
  width: 100%;
  max-width: 800px;
  background: var(--bg-card);
  border: 1px solid var(--mirror-border);
  box-shadow: 0 0 20px rgba(201, 168, 124, 0.06), inset 0 0 30px rgba(201, 168, 124, 0.02);
  display: flex;
  flex-direction: column;
  font-family: var(--font-round);
  color: var(--text-primary);
  font-size: 13px;
  line-height: 1.5;
  margin: 0 auto;
  letter-spacing: 0.02em;
}

/* 环境栏 */
.env-strip {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
  padding: 7px 14px;
  background: var(--bg-deep);
  border-bottom: 1px solid var(--border);
  font-size: 0.8rem;
}

.env-icon {
  margin-right: 4px;
  font-size: 0.72rem;
  opacity: 0.6;
}

.env-item {
  color: var(--text-secondary);
  display: inline-flex;
  align-items: center;
}

.env-divider {
  color: var(--text-dim);
  font-size: 0.65rem;
}

.env-privacy {
  display: inline-flex;
  align-items: center;
  gap: 2px;

  .star {
    color: var(--text-dim);
    font-size: 0.75rem;
    transition: color 0.3s;
    &.filled { color: var(--gold); text-shadow: 0 0 4px rgba(201, 168, 124, 0.4); }
  }
}

.env-phase-tag {
  margin-left: auto;
  background: linear-gradient(135deg, rgba(192, 57, 43, 0.3), rgba(201, 168, 124, 0.15));
  border: 1px solid rgba(201, 168, 124, 0.3);
  color: var(--gold-light);
  padding: 2px 10px;
  font-size: 0.72rem;
  border-radius: 12px;
}

/* 双栏 */
.dual-panel {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0;
}

.char-col {
  padding: 12px 14px;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.char-ying {
  border-right: 1px solid var(--border);
}

.char-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  padding-bottom: 8px;
  border-bottom: 1px solid var(--border);
}

.char-name {
  font-size: 1.05rem;
  font-weight: 700;
  letter-spacing: 3px;
}

.char-ying .char-name {
  color: var(--gold-light);
  text-shadow: 0 0 10px rgba(201, 168, 124, 0.3);
}

.char-barbara .char-name {
  color: var(--crimson-light);
  text-shadow: 0 0 10px rgba(255, 107, 107, 0.3);
}

.phase-badge, .mode-badge {
  padding: 3px 10px;
  font-size: 0.7rem;
  border-radius: 12px;
}

.phase-badge.ying {
  background: rgba(201, 168, 124, 0.12);
  border: 1px solid rgba(201, 168, 124, 0.25);
  color: var(--gold);
}

.mode-badge {
  background: rgba(192, 57, 43, 0.12);
  border: 1px solid rgba(192, 57, 43, 0.25);
  color: var(--crimson-light);
}

/* 数值条 */
.stat-group {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.stat-row {
  display: flex;
  align-items: center;
  gap: 8px;
}

.stat-icon {
  font-size: 0.7rem;
  width: 14px;
  text-align: center;
  opacity: 0.7;
  margin-right: 2px;
}

.stat-label {
  width: 52px;
  font-size: 0.75rem;
  color: var(--text-secondary);
  text-align: left;
  flex-shrink: 0;
  display: flex;
  align-items: center;
}

.stat-track {
  flex: 1;
  height: 8px;
  background: var(--bg-deep);
  border: 1px solid var(--border);
  border-radius: 4px;
  overflow: hidden;
}

.stat-fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.5s ease;
}

.stat-fill.danger {
  animation: pulse-danger 2s infinite;
}

.stat-fill-pink {
  background: linear-gradient(90deg, #6b1a3a, #e91e63);
}

.stat-fill-teal {
  background: linear-gradient(90deg, #1a3a3a, #1abc9c);
}

.stat-value {
  width: 34px;
  font-size: 0.72rem;
  color: var(--text-secondary);
  text-align: left;
  flex-shrink: 0;
  font-family: var(--font-mono);
  letter-spacing: 0;
}

.text-crimson {
  color: var(--crimson-light) !important;
}

@keyframes pulse-danger {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}

/* 状态标签 */
.status-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
}

.tag {
  padding: 2px 8px;
  font-size: 0.7rem;
  border-radius: 10px;
}

.tag-icon {
  margin-right: 3px;
  font-size: 0.62rem;
}

.tag-standard {
  background: rgba(201, 168, 124, 0.1);
  border: 1px solid rgba(201, 168, 124, 0.2);
  color: var(--gold);
}

.tag-abnormal {
  background: rgba(192, 57, 43, 0.1);
  border: 1px solid rgba(192, 57, 43, 0.2);
  color: var(--crimson-light);
}

/* 子章节 */
.subsection {
  border-top: 1px dashed var(--border);
  padding-top: 8px;
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.subsection-title {
  font-size: 0.72rem;
  color: var(--gold-dim);
  letter-spacing: 2.5px;
  margin-bottom: 2px;
  display: flex;
  align-items: center;
  gap: 5px;
}

/* 服装 */
.outfit-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4px 10px;
}

.outfit-item {
  font-size: 0.75rem;
  color: var(--text-secondary);
  line-height: 1.5;
}

.outfit-key {
  color: var(--text-dim);
  margin-right: 5px;
  font-size: 0.68rem;
}

.outfit-extras {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
  margin-top: 3px;
}

.expose-tag {
  font-size: 0.68rem;
  color: var(--crimson-light);
  padding: 2px 7px;
  background: rgba(192, 57, 43, 0.08);
  border: 1px solid rgba(192, 57, 43, 0.2);
  border-radius: 8px;
  display: flex;
  align-items: center;
  gap: 3px;
}

.bind-tag {
  font-size: 0.68rem;
  color: var(--gold);
  padding: 2px 7px;
  background: rgba(201, 168, 124, 0.08);
  border: 1px solid rgba(201, 168, 124, 0.2);
  border-radius: 8px;
  display: flex;
  align-items: center;
  gap: 3px;
}

.acc-tag {
  font-size: 0.68rem;
  color: var(--text-secondary);
  display: flex;
  align-items: center;
  gap: 3px;
}

/* 评价框 */
.eval-box {
  border: 1px solid var(--border);
  background: var(--mirror);
  border-radius: 8px;
  padding: 8px 10px;
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.eval-label {
  font-size: 0.65rem;
  color: var(--gold-dim);
  letter-spacing: 2px;
  display: flex;
  align-items: center;
  gap: 4px;
}

.eval-text {
  font-size: 0.75rem;
  color: var(--gold-light);
  font-style: italic;
  line-height: 1.5;
}

/* 道具 & 经历（芭芭拉栏内联） */
.tool-item {
  font-size: 0.72rem;
  color: var(--text-secondary);
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 2px 0;
}

.history-inline {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  margin-top: 2px;
}

.history-tag {
  padding: 1px 7px;
  font-size: 0.66rem;
  border-radius: 10px;
}

.tag-barbara {
  background: rgba(192, 57, 43, 0.1);
  border: 1px solid rgba(192, 57, 43, 0.2);
  color: var(--crimson-light);
}

.tag-ying {
  background: rgba(201, 168, 124, 0.1);
  border: 1px solid rgba(201, 168, 124, 0.2);
  color: var(--gold);
}

@media (max-width: 600px) {
  .dual-panel {
    grid-template-columns: 1fr;
  }

  .char-ying {
    border-right: none;
    border-bottom: 1px solid var(--border);
  }
}
